  ('elementary-64311456-moex-00776', 'elementary-64311456', 'elementary-64311456-moex-111-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', '醫務社會工作者對於需要危機處遇的病人，下列敘述何者錯誤？', '["立即給予支持同理與傾聽，並且建立信任的專業關係", "透過會談以瞭解病患的危機因素，以及優先協助處理事項", "在會談中協助病患認識問題，由醫務社會工作者自行決定處遇策略", "持續協助病患，待任務完成評估出院或轉介服務"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:11+00:00", "source_pdf_sha1": "2fbac3fb0314", "answer_pdf_sha1": "ec43feddf564", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "502", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
